13939     // handle the interesting cases from buildTree here. If an operand is an
13940     // instruction we haven't yet visited and from the same basic block as the
13941     // user or the use is a PHI node, we add it to the worklist.
13942     else if (isa<PHINode, CastInst, GetElementPtrInst, CmpInst, SelectInst,
13943                  BinaryOperator, UnaryOperator>(I)) {
